import React, { useState, useEffect } from 'react';
import axios from 'axios';
import MemberForm from './components/MemberForm';
import CollectionSheet from './components/CollectionSheet';
import './App.css';

function App() {
  const [members, setMembers] = useState([]);
  const [selectedMember, setSelectedMember] = useState(null);
  const [showForm, setShowForm] = useState(false);

  useEffect(() => {
    fetchMembers();
  }, []);

  const fetchMembers = async () => {
    try {
      const res = await axios.get('/api/members');
      setMembers(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const handleMemberCreated = () => {
    fetchMembers();
    setShowForm(false);
  };

  return (
    <div className="app">
      <header className="header">
        <h1>Chit Collection Management</h1>
        <button onClick={() => setShowForm(!showForm)} className="btn-primary">
          {showForm ? 'Cancel' : 'Add Member'}
        </button>
      </header>

      {showForm && <MemberForm onSuccess={handleMemberCreated} />}

      <div className="content">
        <div className="sidebar">
          <h2>Members</h2>
          {members.map(member => (
            <div
              key={member.id}
              className={`member-item ${selectedMember?.id === member.id ? 'active' : ''}`}
              onClick={() => setSelectedMember(member)}
            >
              <strong>{member.name}</strong>
              <small>{member.member_number}</small>
            </div>
          ))}
        </div>

        <div className="main-content">
          {selectedMember ? (
            <CollectionSheet member={selectedMember} />
          ) : (
            <div className="placeholder">Select a member to view collection sheet</div>
          )}
        </div>
      </div>
    </div>
  );
}

export default App;
